    def type_city(
        self,
        locator,
        city
    ):

        for attempt in range(3):

            try:

                field = WebDriverWait(
                    self.driver,
                    30
                ).until(
                    EC.element_to_be_clickable(
                        locator
                    )
                )

                self.driver.execute_script(
                    "arguments[0].click();",
                    field
                )

                logger.info(
                    f"CLICKED FIELD: {city}"
                )

                time.sleep(1)

                active = self.driver.switch_to.active_element

                active.send_keys(
                    Keys.CONTROL + "a"
                )

                active.send_keys(
                    Keys.DELETE
                )

                active.send_keys(city)

                logger.info(
                    f"TYPED CITY: {city}"
                )

                suggestions = WebDriverWait(
                    self.driver,
                    30
                ).until(
                    EC.presence_of_all_elements_located(
                        (
                            By.XPATH,
                            "//ul/li"
                        )
                    )
                )

                for item in suggestions:

                    try:

                        text = item.text.strip()

                        if city.lower() in text.lower():

                            self.driver.execute_script(
                                "arguments[0].click();",
                                item
                            )

                            logger.info(
                                f"SELECTED CITY: {text}"
                            )

                            time.sleep(2)

                            return

                    except:
                        continue

                raise Exception(
